const { execSync } = require('child_process');
const repoPath = '/root/.openclaw/workspace/projects/agent-studio';
try {
  const out = execSync(`python3 ${repoPath}/skills/git-automation/repo_health.py --repo ${repoPath}`).toString();
  return [{json: {health: out}}];
} catch(e) {
  return [{json: {health: e.stdout || e.message}}];
}

const { execSync } = require('child_process');
const repoPath = '/root/.openclaw/workspace/projects/agent-studio';
try {
  const diff = execSync('cd ' + repoPath + ' && git diff --cached', {encoding:'utf8', timeout: 5000});
  return [{json: {hasChanges: diff.length > 0, diff}}];
} catch(e) {
  return [{json: {hasChanges: false}}];
}

const { execSync } = require('child_process');
const repoPath = '/root/.openclaw/workspace/projects/agent-studio';
try {
  const diff = execSync('cd ' + repoPath + ' && git diff --cached', {encoding:'utf8', timeout: 5000});
  if (!diff.trim()) return [{json: {message: null, skip: true}}];
  const msg = execSync(`echo '${diff.replace(/'/g, "'\\''" )}' | python3 ${repoPath}/skills/git-automation/commit_message.py --stdin`, {encoding:'utf8', timeout: 10000});
  return [{json: {message: msg.split('To use:')[0].trim(), skip: false}}];
} catch(e) {
  return [{json: {message: null, skip: true, error: e.message}}];
}
